def _dispatch_bg_job(args):
    try:
        import background_jobs as bg
        action = args["action"]

        if action == "schedule":
            name = args["name"]
            cmd = args["command"]
            interval = args.get("interval", 60)
            run_now = args.get("run_now", False)
            bg.schedule_shell(name, cmd, interval, run_now)
            return f"✅ Scheduled job '{name}' every {interval}s"

        elif action == "daemon":
            name = args["name"]
            cmd = args["command"]
            interval = args.get("interval", 5)
            bg.start_daemon(name, lambda: __import__("subprocess").run(
                cmd, shell=True, capture_output=True, text=True, timeout=300
            ), interval)
            return f"✅ Daemon '{name}' started (interval {interval}s)"

        elif action == "oneshot":
            cmd = args["command"]
            timeout = args.get("timeout", 300)
            bg.run_shell_once(cmd, timeout)
            return f"✅ Oneshot job fired"

        elif action == "status":
            jobs = bg.status()
            if not jobs:
                return "No active background jobs"
            lines = []
            for name, info in jobs.items():
                lines.append(f"  {name}: type={info.get('type')}, runs={info.get('run_count',0)}, errors={info.get('error_count',0)}")
            return "\n".join(lines)

        elif action == "remove":
            name = args["name"]
            return "✅ Removed" if bg.remove(name) else f"[error] Job '{name}' not found"

        elif action == "stop_all":
            bg.stop_all()
            return "✅ All background jobs stopped"

        return f"[error] Unknown action: {action}"
    except Exception as e:
        return f"[error] bg_job gagal: {e}"

